function getDifficultyColor(d) {
  return d === "Easy" ? "#5a9e40" : d === "Medium" ? "#d4922a" : "#c94030";
}

function formatNum(n) {
  if (n === 0) return "0";
  if (Math.abs(n - Math.round(n)) < 0.05) return Math.round(n).toString();
  if (Math.abs(n - 0.125) < 0.04) return "⅛";
  if (Math.abs(n - 0.25)  < 0.04) return "¼";
  if (Math.abs(n - 0.333) < 0.04) return "⅓";
  if (Math.abs(n - 0.5)   < 0.04) return "½";
  if (Math.abs(n - 0.667) < 0.04) return "⅔";
  if (Math.abs(n - 0.75)  < 0.04) return "¾";
  return parseFloat(n.toFixed(1)).toString();
}

function formatAmount(val, unit, imperial) {
  if (imperial) {
    if (unit === "g")  return `${formatNum(val / 28.3495)} oz`;
    if (unit === "ml") return `${formatNum(val / 29.5735)} fl oz`;
  }
  const label = {
    g: "g", ml: "ml", tsp: "tsp", tbsp: "tbsp", piece: "",
    sprig:  val === 1 ? "sprig"  : "sprigs",
    clove:  val === 1 ? "clove"  : "cloves",
    fillet: val === 1 ? "fillet" : "fillets",
    pinch:  val === 1 ? "pinch"  : "pinches",
  }[unit] ?? unit;
  return `${formatNum(val)}${label ? " " + label : ""}`.trim();
}

function aggregateIngredients(ids) {
  const map = new Map();
  for (const id of ids) {
    const s = SAUCES.find(x => x.id === id);
    if (!s) continue;
    for (const ing of s.ingredients) {
      const key = `${ing.name.toLowerCase().trim()}||${ing.unit}`;
      if (map.has(key)) {
        const ex = map.get(key);
        ex.value += ing.value;
        if (!ex.sauces.includes(s.name)) ex.sauces.push(s.name);
      } else {
        map.set(key, { ...ing, sauces: [s.name] });
      }
    }
  }
  return [...map.values()].sort((a, b) => a.name.localeCompare(b.name));
}


