export default function SaucierApp() {
  const [selected,      setSelected]      = useState(null);
  const [search,        setSearch]        = useState("");
  const [catFilter,     setCatFilter]     = useState("all");
  const [diffFilter,    setDiffFilter]    = useState("all");
  const [techFilter,    setTechFilter]    = useState("all");
  const [activeTab,     setActiveTab]     = useState("ingredients");
  const [showTree,      setShowTree]      = useState(false);
  const [servings,      setServings]      = useState(null);
  const [isImperial,    setIsImperial]    = useState(false);
  const [favorites,     setFavorites]     = useState(() => { try { const s = localStorage.getItem("lsc_fav");   return s ? new Set(JSON.parse(s)) : new Set(); } catch { return new Set(); } });
  const [shopList,      setShopList]      = useState(() => { try { const s = localStorage.getItem("lsc_shop");  return s ? new Set(JSON.parse(s)) : new Set(); } catch { return new Set(); } });
  const [showShop,      setShowShop]      = useState(false);
  const [recentlyViewed,setRecentlyViewed]= useState(() => { try { return JSON.parse(localStorage.getItem("lsc_recent") || "[]"); } catch { return []; } });
  const [completedSteps,setCompletedSteps]= useState(() => { try { return JSON.parse(localStorage.getItem("lsc_steps")  || "{}"); } catch { return {}; } });   // { [sauceId_stepIdx]: true }
  const [cookingMode,   setCookingMode]   = useState(false); // fullscreen step-by-step
  const [cookStep,      setCookStep]      = useState(0);
  const [sortBy,        setSortBy]        = useState("default"); // default | az | za | time | difficulty
  const [viewMode,      setViewMode]      = useState("grid"); // grid | list
  const [userNotes,     setUserNotes]     = useState(() => { try { return JSON.parse(localStorage.getItem("lsc_notes") || "{}"); } catch { return {}; } });    // { [sauceId]: string }
  const [editingNote,   setEditingNote]   = useState(false);
  const [noteText,      setNoteText]      = useState("");
  const [ingSearch,     setIngSearch]     = useState(null);  // ingredient name being cross-referenced
  const [compareId,     setCompareId]     = useState(null);  // sauce id to compare against
  const [showCompare,   setShowCompare]   = useState(false);
  const [timerSecs,     setTimerSecs]     = useState(null);  // null = no timer active
  const [timerRunning,  setTimerRunning]  = useState(false);
  const [timerDone,     setTimerDone]     = useState(false);
  const [ratings,       setRatings]       = useState(() => { try { return JSON.parse(localStorage.getItem("lsc_ratings") || "{}"); } catch { return {}; } }); // { [sauceId]: 1-5 }
  const [darkMode,      setDarkMode]      = useState(() => { try { return localStorage.getItem("lsc_dark") === "1"; } catch { return false; } });
  const [toasts,        setToasts]        = useState([]);
  const [achievements,  setAchievements]  = useState(() => { try { return JSON.parse(localStorage.getItem("lsc_ach") || "[]"); } catch { return []; } });
  const searchRef = useRef(null);
  const noteRef   = useRef(null);
  const timerRef  = useRef(null);

  const addToast = useCallback((msg, icon = "✓") => {
    const id = Date.now() + Math.random();
    setToasts(prev => [...prev, { id, msg, icon }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3800);
  }, []);

  const sauce       = selected ? SAUCES.find(s => s.id === selected) : null;
  const baseServings= sauce?.servings ?? 4;
  const curServings = servings ?? baseServings;
  const scale       = sauce ? curServings / baseServings : 1;

  // Keyboard navigation
  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") {
        if (cookingMode) { setCookingMode(false); return; }
        if (showCompare) { setShowCompare(false); return; }
        if (ingSearch)   { setIngSearch(null); return; }
        if (showShop)    { setShowShop(false); return; }
        if (selected)    { setSelected(null); return; }
        if (showTree)    { setShowTree(false); return; }
      }
      if (e.key === "/" && document.activeElement.tagName !== "INPUT") {
        e.preventDefault();
        searchRef.current?.focus();
      }
      const inInput = ["INPUT","TEXTAREA"].includes(document.activeElement.tagName);
      if (!inInput && !e.ctrlKey && !e.metaKey && e.key === "d") { setDarkMode(m => !m); }
      if (!inInput && !e.ctrlKey && !e.metaKey && e.key === "r" && !cookingMode) {
        e.preventDefault();
        navigateTo(SAUCES[Math.floor(Math.random() * SAUCES.length)].id);
      }
      if (cookingMode && sauce) {
        if (e.key === "ArrowRight" || e.key === "ArrowDown") setCookStep(s => Math.min(s + 1, sauce.steps.length - 1));
        if (e.key === "ArrowLeft"  || e.key === "ArrowUp")   setCookStep(s => Math.max(s - 1, 0));
        if (e.key === " ") { e.preventDefault(); toggleStep(sauce.id, cookStep); }
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [selected, showTree, showShop, cookingMode, cookStep, sauce]);

  const toggleStep = useCallback((sauceId, idx) => {
    const key = `${sauceId}_${idx}`;
    setCompletedSteps(prev => { const n = {...prev}; n[key] ? delete n[key] : (n[key] = true); return n; });
  }, []);

  const clearSteps = (sauceId) => setCompletedSteps(prev => {
    const n = {...prev};
    Object.keys(n).filter(k => k.startsWith(sauceId + "_")).forEach(k => delete n[k]);
    return n;
  });

  const startCooking = () => { setCookStep(0); setCookingMode(true); setActiveTab("method"); };

  // Extract suggested timer from step text
  function extractStepTime(text) {
    // Match patterns like "8–10 minutes", "2 minutes", "45–60 minutes", "1 hour"
    const m = text.match(/(\d+)[\u2013\-]?(\d+)?\s*(minutes?|mins?|hours?|hrs?)/i);
    if (!m) return null;
    const hi = m[2] ? parseInt(m[2]) : parseInt(m[1]);
    const unit = m[3].toLowerCase();
    return unit.startsWith("h") ? hi * 60 : hi;
  }

  // Timer effect
  useEffect(() => {
    if (timerRunning && timerSecs !== null && timerSecs > 0) {
      timerRef.current = setTimeout(() => setTimerSecs(s => s - 1), 1000);
    } else if (timerSecs === 0 && timerRunning) {
      setTimerRunning(false);
      setTimerDone(true);
    }
    return () => clearTimeout(timerRef.current);
  }, [timerSecs, timerRunning]);

  const startTimer = (secs) => { setTimerSecs(secs * 60); setTimerRunning(true); setTimerDone(false); };
  const pauseTimer = () => setTimerRunning(r => !r);
  const resetTimer = (secs) => { setTimerSecs(secs * 60); setTimerRunning(false); setTimerDone(false); };

  // When step changes, reset timer
  useEffect(() => {
    setTimerSecs(null); setTimerRunning(false); setTimerDone(false);
  }, [cookStep, selected]);

  // Persist user data to localStorage
  useEffect(() => { try { localStorage.setItem("lsc_fav",    JSON.stringify([...favorites]));       } catch {} }, [favorites]);
  useEffect(() => { try { localStorage.setItem("lsc_shop",   JSON.stringify([...shopList]));        } catch {} }, [shopList]);
  useEffect(() => { try { localStorage.setItem("lsc_steps",  JSON.stringify(completedSteps));       } catch {} }, [completedSteps]);
  useEffect(() => { try { localStorage.setItem("lsc_notes",  JSON.stringify(userNotes));            } catch {} }, [userNotes]);
  useEffect(() => { try { localStorage.setItem("lsc_recent",   JSON.stringify(recentlyViewed));     } catch {} }, [recentlyViewed]);
  useEffect(() => { try { localStorage.setItem("lsc_ratings",  JSON.stringify(ratings));            } catch {} }, [ratings]);
  useEffect(() => { try { localStorage.setItem("lsc_dark",     darkMode ? "1" : "0");               } catch {} }, [darkMode]);
  useEffect(() => { try { localStorage.setItem("lsc_ach",      JSON.stringify(achievements));        } catch {} }, [achievements]);

  // Check and unlock achievements (read achievements from ref to avoid dep-loop)
  const achRef = useRef(achievements);
  useEffect(() => { achRef.current = achievements; }, [achievements]);

  useEffect(() => {
    const cooked = new Set(SAUCES.filter(s => s.steps.length > 0 && s.steps.every((_, i) => completedSteps[`${s.id}_${i}`])).map(s => s.id));
    const newOnes = ACHIEVEMENTS.filter(a => !achRef.current.includes(a.id) && a.check(cooked, favorites, ratings));
    if (newOnes.length > 0) {
      setAchievements(prev => [...prev, ...newOnes.map(a => a.id)]);
      newOnes.forEach((a, i) => setTimeout(() => addToast(`${a.label} unlocked!`, a.icon), i * 700 + 300));
    }
  }, [completedSteps, favorites, ratings]);

  const navigateTo = (id) => {
    setSelected(id);
    setActiveTab("ingredients");
    setShowTree(false);
    setServings(null);
    setShowShop(false);
    setCookingMode(false);
    setCookStep(0);
    setRecentlyViewed(prev => [id, ...prev.filter(x => x !== id)].slice(0, 8));
  };

  const toggleFav  = (id, e) => { if (e) e.stopPropagation(); const adding = !favorites.has(id); setFavorites(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; }); addToast(adding ? "Added to favourites" : "Removed from favourites", adding ? "♥" : "♡"); };
  const toggleShop = (id, e) => { if (e) e.stopPropagation(); const adding = !shopList.has(id);  setShopList(prev  => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; }); addToast(adding ? "Added to shopping list" : "Removed from list", adding ? "🛒" : "✕"); };

  const openNote = (id) => {
    setNoteText(userNotes[id] ?? "");
    setEditingNote(true);
    setTimeout(() => noteRef.current?.focus(), 50);
  };
  const saveNote = (id) => {
    setUserNotes(prev => ({ ...prev, [id]: noteText }));
    setEditingNote(false);
  };
  const deleteNote = (id) => { setUserNotes(prev => { const n = {...prev}; delete n[id]; return n; }); setEditingNote(false); };

  const filtered = SAUCES.filter(s => {
    const q = search.toLowerCase();
    const matchQ = !search || s.name.toLowerCase().includes(q) || s.tagline.toLowerCase().includes(q) || s.description.toLowerCase().includes(q);
    const matchC = catFilter === "all" || (catFilter === "saved" ? favorites.has(s.id) : s.category === catFilter);
    const matchD = diffFilter === "all" || s.difficulty === diffFilter;
    const matchT = techFilter === "all" || getSauceTechniques(s).includes(techFilter);
    return matchQ && matchC && matchD && matchT;
  });

  const DIFF_ORDER = { "Easy": 0, "Medium": 1, "Advanced": 2 };
  function timeToMin(t) { const m = t.match(/(\d+\.?\d*)/); return m ? parseFloat(m[1]) * (t.includes("hr") ? 60 : 1) : 0; }

  const sortedFiltered = [...filtered].sort((a, b) => {
    if (sortBy === "az") return a.name.localeCompare(b.name);
    if (sortBy === "za") return b.name.localeCompare(a.name);
    if (sortBy === "time") return timeToMin(a.time) - timeToMin(b.time);
    if (sortBy === "difficulty") return DIFF_ORDER[a.difficulty] - DIFF_ORDER[b.difficulty];
    return 0;
  });

  // Cooked = sauce where all steps are completed
  const cookedIds = new Set(SAUCES.filter(s => s.steps.length > 0 && s.steps.every((_, i) => completedSteps[`${s.id}_${i}`])).map(s => s.id));

  // Sauces using a given ingredient (for cross-reference)
  const saucesWithIng = ingSearch
    ? SAUCES.filter(s => s.ingredients.some(ing => ing.name.toLowerCase().includes(ingSearch.toLowerCase())))
    : [];

  // Sauce of the day — deterministic based on date
  const sauceOfDay = (() => {
    const d = new Date(); const dayNum = Math.floor(d / 86400000);
    return SAUCES[dayNum % SAUCES.length];
  })();

  const compareSauce = compareId ? SAUCES.find(s => s.id === compareId) : null;

  const goRandom = () => {
    const pool = filtered.length > 0 ? filtered : SAUCES;
    navigateTo(pool[Math.floor(Math.random() * pool.length)].id);
  };

  const shopIngredients = aggregateIngredients([...shopList]);

  const ratesSauce = (id, star) => {
    const labels = ["","Poor","Fair","Good","Great","Perfect"];
    const removing = ratings[id] === star;
    setRatings(prev => removing ? (({ [id]: _, ...rest }) => rest)(prev) : { ...prev, [id]: star });
    addToast(removing ? "Rating cleared" : `Rated: ${labels[star]}`, removing ? "☆" : "⭐");
  };

  return (
    <div style={{ fontFamily:"'Georgia','Times New Roman',serif", background: darkMode ? "#111827" : "#eef2f8", minHeight:"100vh", color: darkMode ? "#e2e8f0" : "#1a2540", transition:"background .3s, color .3s" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&family=Crimson+Text:ital,wght@0,400;0,600;1,400&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:#dde6f0}::-webkit-scrollbar-thumb{background:#9ab2cc;border-radius:3px}
        .sc{background:#fff;border:1px solid #cdd8ea;border-radius:10px;padding:15px;cursor:pointer;transition:all .22s;position:relative;overflow:hidden}
        .sc:hover{border-color:#4878c0;transform:translateY(-3px);box-shadow:0 10px 32px rgba(30,70,160,.13)}
        .sc::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:var(--ac);border-radius:10px 10px 0 0}
        .pill{display:inline-block;padding:2px 9px;border-radius:20px;font-size:11px;font-family:'Crimson Text',serif;letter-spacing:.4px}
        .tb{background:none;border:none;color:#7888a8;cursor:pointer;padding:8px 16px;font-family:'Crimson Text',serif;font-size:15px;border-bottom:2px solid transparent;transition:all .2s}
        .tb.on{color:#2060b0;border-bottom-color:#2060b0}
        .tb:hover{color:#1a2540}
        .fb{background:#fff;border:1px solid #ccd6e8;color:#7888a8;cursor:pointer;padding:5px 13px;border-radius:20px;font-family:'Crimson Text',serif;font-size:13px;transition:all .2s;white-space:nowrap}
        .fb.on{background:#e4edf9;border-color:#4878c0;color:#2060b0;font-weight:600}
        .fb:hover:not(.on){border-color:#8aaad8;color:#1a2540}
        .mb{background:#fff;border:1px solid #cdd8ea;color:#2060b0;cursor:pointer;width:28px;height:28px;border-radius:5px;font-size:17px;display:flex;align-items:center;justify-content:center;transition:all .15s;flex-shrink:0}
        .mb:hover:not(:disabled){background:#e4edf9;border-color:#4878c0}
        .mb:disabled{opacity:.25;cursor:default}
        .ctag{display:inline-block;margin:3px;padding:3px 11px;background:#e8f4fb;border:1px solid #9cc8e0;border-radius:4px;font-size:13px;cursor:pointer;color:#1870a0;font-family:'Crimson Text',serif;transition:all .15s}
        .ctag:hover{background:#d0e8f5;border-color:#2890c0}
        .tn{background:#fff;border:1px solid #cdd8ea;border-radius:6px;padding:6px 12px;cursor:pointer;transition:all .2s;display:inline-block;font-family:'Crimson Text',serif;font-size:13px;color:#3a5070}
        .tn:hover{border-color:#4878c0;color:#2060b0;background:#f0f6fd}
        .bk{background:none;border:1px solid #cdd8ea;color:#7888a8;cursor:pointer;padding:5px 13px;border-radius:20px;font-family:'Crimson Text',serif;font-size:13px;transition:all .2s}
        .bk:hover{border-color:#4878c0;color:#2060b0}
        .act{background:none;border:1px solid transparent;cursor:pointer;border-radius:6px;display:flex;align-items:center;justify-content:center;transition:all .15s;flex-shrink:0}
        .act:hover{background:#e8f2fb;border-color:#9ac0e0}
        input{background:#fff;border:1px solid #cdd8ea;color:#1a2540;padding:8px 14px;border-radius:20px;font-family:'Crimson Text',serif;font-size:15px;outline:none;transition:border-color .2s;width:100%}
        input:focus{border-color:#4878c0;box-shadow:0 0 0 3px rgba(72,120,192,.1)}
        input::placeholder{color:#a0b4c8}
        .overlay{position:fixed;inset:0;background:rgba(20,35,70,.45);z-index:200;display:flex;justify-content:flex-end;animation:fadeIn .2s}
        .panel{background:#fff;width:min(440px,100vw);height:100vh;overflow-y:auto;box-shadow:-8px 0 32px rgba(0,0,0,.15);animation:slideIn .25s}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes slideIn{from{transform:translateX(100%)}to{transform:translateX(0)}}
        .badge{display:inline-flex;align-items:center;justify-content:center;background:#2060b0;color:#fff;border-radius:10px;font-size:10px;font-family:'Crimson Text',serif;min-width:18px;height:18px;padding:0 4px;line-height:1}
        .cat-chip{background:#fff;border:1px solid #cdd8ea;cursor:pointer;padding:5px 14px;border-radius:20px;font-family:'Crimson Text',serif;font-size:13px;color:#6070a0;transition:all .15s;display:flex;align-items:center;gap:5px;white-space:nowrap}
        .cat-chip.on{border-color:#4878c0;color:#2060b0;background:#e4edf9}
        .cat-chip:hover:not(.on){border-color:#9ab4d0;color:#1a2540}
        .star-btn{background:none;border:none;cursor:pointer;font-size:18px;padding:1px 2px;line-height:1;transition:transform .1s}
        .star-btn:hover{transform:scale(1.25)}
        .toast-enter{animation:toastIn .3s cubic-bezier(.175,.885,.32,1.275)}
        .toast-exit{animation:toastOut .35s ease forwards}
        @keyframes toastIn{from{opacity:0;transform:translateX(80px) scale(.9)}to{opacity:1;transform:translateX(0) scale(1)}}
        @keyframes toastOut{from{opacity:1;transform:translateX(0)}to{opacity:0;transform:translateX(80px)}}
        ${darkMode ? `
          .sc{background:#1e2a3e!important;border-color:#2d3f5a!important;color:#e2e8f0!important}
          .sc:hover{border-color:#4878c0!important;box-shadow:0 10px 32px rgba(0,0,0,.4)!important}
          .fb,.bk,.tb,.mb,.tn,.ctag,.cat-chip{background:#1e2a3e!important;border-color:#2d3f5a!important;color:#94aac4!important}
          .fb.on,.cat-chip.on{background:#1a3060!important;border-color:#4878c0!important;color:#7ab4f0!important}
          .overlay{background:rgba(0,0,0,.65)!important}
          .panel{background:#111827!important}
          input{background:#1e2a3e!important;border-color:#2d3f5a!important;color:#e2e8f0!important}
          input::placeholder{color:#4a6080!important}
          .badge{background:#2a5090!important}
        ` : ""}
      `}</style>

      {/* ─── Header ─── */}
      <div style={{ background:"#fff", borderBottom:"1px solid #cdd8ea", padding:"12px 20px", position:"sticky", top:0, zIndex:100 }}>
        <div style={{ maxWidth:980, margin:"0 auto", display:"flex", alignItems:"center", gap:12, flexWrap:"wrap" }}>
          {/* Title */}
          <div style={{ display:"flex", alignItems:"baseline", gap:8, flexShrink:0 }}>
            <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:19, fontWeight:700, color:"#1a3060", letterSpacing:"-.3px" }}>
              Saucier
            </h1>
            <span style={{ color:"#b0c0d8", fontSize:11, fontFamily:"'Crimson Text',serif", fontStyle:"italic" }}>Les Sauces Françaises · {SAUCES.length}</span>
          </div>

          {/* Search */}
          <div style={{ flex:1, minWidth:160, maxWidth:300 }}>
            <input
              type="text"
              placeholder="Search sauces, techniques…"
              value={search}
              onChange={e => { setSearch(e.target.value); setSelected(null); setShowTree(false); }}
              ref={searchRef}
            />
          </div>

          {/* Right actions */}
          <div style={{ display:"flex", gap:8, alignItems:"center", flexShrink:0, flexWrap:"wrap" }}>
            <button className="bk" onClick={() => setDarkMode(d => !d)} title="Toggle dark mode" style={{ fontSize:15, padding:"5px 10px" }}>
              {darkMode ? "☀️" : "🌙"}
            </button>
            <button className="bk" onClick={goRandom} title="Discover a random sauce" style={{ display:"flex", alignItems:"center", gap:5 }}>
              ✦ Random
            </button>
            <button className={`bk ${showTree?"on":""}`} onClick={() => { setShowTree(!showTree); setSelected(null); }}>
              {showTree ? "▲ Tree" : "▼ Tree"}
            </button>
            {sauce && <button className="bk" onClick={() => setSelected(null)}>← Back</button>}
            <button
              className="bk"
              onClick={() => setShowShop(!showShop)}
              style={{ position:"relative", display:"flex", alignItems:"center", gap:6, ...(shopList.size > 0 ? { borderColor:"#4878c0", color:"#2060b0" } : {}) }}
            >
              🛒
              {shopList.size > 0 && <span className="badge">{shopList.size}</span>}
            </button>
            {favorites.size > 0 && (
              <button
                className={`bk ${catFilter === "saved" ? "on" : ""}`}
                onClick={() => { setCatFilter(catFilter === "saved" ? "all" : "saved"); setSelected(null); }}
                style={{ display:"flex", alignItems:"center", gap:5 }}
              >
                ♥ <span className="badge" style={{ background: catFilter === "saved" ? "#fff" : "#2060b0", color: catFilter === "saved" ? "#2060b0" : "#fff" }}>{favorites.size}</span>
              </button>
            )}
          </div>
        </div>
      </div>

      {/* ─── Shopping List Panel ─── */}
      {showShop && (
        <div className="overlay" onClick={() => setShowShop(false)}>
          <div className="panel" onClick={e => e.stopPropagation()}>
            <div style={{ padding:"20px 22px", borderBottom:"1px solid #e0e8f4", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:18, color:"#1a3060" }}>Shopping List</h2>
              <button className="bk" onClick={() => setShowShop(false)}>✕</button>
            </div>
            {shopList.size === 0 ? (
              <div style={{ padding:"40px 22px", textAlign:"center", color:"#a0b4c8", fontFamily:"'Crimson Text',serif", fontStyle:"italic", fontSize:15 }}>
                Add sauces with the + button to build your shopping list
              </div>
            ) : (
              <>
                {/* Sauce tags in list */}
                <div style={{ padding:"14px 22px", borderBottom:"1px solid #edf2f9", display:"flex", flexWrap:"wrap", gap:6 }}>
                  {[...shopList].map(id => {
                    const s = SAUCES.find(x => x.id === id);
                    return s ? (
                      <span
                        key={id}
                        onClick={() => toggleShop(id)}
                        style={{ display:"inline-flex", alignItems:"center", gap:5, padding:"3px 10px", background:"#e8f0fb", border:"1px solid #b0ccec", borderRadius:20, fontSize:12, cursor:"pointer", color:"#2060b0", fontFamily:"'Crimson Text',serif" }}
                      >
                        {s.name} <span style={{ fontSize:10, color:"#7890b8" }}>✕</span>
                      </span>
                    ) : null;
                  })}
                  <button
                    onClick={() => setShopList(new Set())}
                    style={{ background:"none", border:"none", color:"#b0a0a0", cursor:"pointer", fontSize:12, fontFamily:"'Crimson Text',serif", padding:"3px 6px" }}
                  >
                    Clear all
                  </button>
                </div>
                {/* Aggregated ingredients */}
                <div style={{ padding:"8px 0" }}>
                  <div style={{ padding:"8px 22px", fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif", letterSpacing:"1px", textTransform:"uppercase" }}>
                    {shopIngredients.length} ingredients
                  </div>
                  {shopIngredients.map((ing, i) => (
                    <div
                      key={i}
                      style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", padding:"9px 22px", borderBottom:"1px solid #f0f5fb", gap:12 }}
                    >
                      <div>
                        <div style={{ fontFamily:"'Crimson Text',serif", fontSize:15, color:"#1a2540" }}>{ing.name}</div>
                        {ing.sauces.length > 1 && (
                          <div style={{ fontSize:11, color:"#b0c0d8", fontFamily:"'Crimson Text',serif", fontStyle:"italic", marginTop:1 }}>
                            {ing.sauces.join(", ")}
                          </div>
                        )}
                      </div>
                      <span style={{ fontFamily:"'Crimson Text',serif", fontSize:14, color:"#2060b0", fontWeight:600, flexShrink:0 }}>
                        {formatAmount(ing.value, ing.unit, isImperial)}
                      </span>
                    </div>
                  ))}
                </div>
                <div style={{ padding:"14px 22px", borderTop:"1px solid #e0e8f4", display:"flex", gap:8 }}>
                  <button className="fb" onClick={() => setIsImperial(!isImperial)} style={{ flex:1 }}>
                    {isImperial ? "→ Metric" : "→ Imperial"}
                  </button>
                  <button className="fb" style={{ flex:1 }} onClick={(e) => {
                    const lines = shopIngredients.map(ing => `${formatAmount(ing.value, ing.unit, isImperial)}  ${ing.name}`);
                    const header = [...shopList].map(id => SAUCES.find(s=>s.id===id)?.name).filter(Boolean).join(", ");
                    navigator.clipboard.writeText(`Shopping List\n${header}\n\n${lines.join("\n")}`).then(() => {
                      const btn = e.currentTarget; btn.textContent = "✓ Copied!";
                      setTimeout(() => { btn.textContent = "📋 Copy list"; }, 1800);
                    });
                  }}>📋 Copy list</button>
                </div>
              </>
            )}
          </div>
        </div>
      )}

      {/* ─── Ingredient Cross-Reference Panel ─── */}
      {ingSearch && (
        <div className="overlay" onClick={() => setIngSearch(null)}>
          <div className="panel" onClick={e => e.stopPropagation()}>
            <div style={{ padding:"20px 22px", borderBottom:"1px solid #e0e8f4", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, color:"#1a3060" }}>Sauces using</h2>
                <p style={{ fontFamily:"'Crimson Text',serif", fontStyle:"italic", color:"#4878c0", fontSize:15, marginTop:2 }}>{ingSearch}</p>
              </div>
              <button className="bk" onClick={() => setIngSearch(null)}>✕</button>
            </div>
            {saucesWithIng.length === 0 ? (
              <div style={{ padding:"40px 22px", textAlign:"center", color:"#a0b4c8", fontFamily:"'Crimson Text',serif", fontStyle:"italic" }}>No matches found</div>
            ) : (
              <div style={{ padding:"8px 0" }}>
                <div style={{ padding:"8px 22px", fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif", letterSpacing:"1px", textTransform:"uppercase" }}>
                  {saucesWithIng.length} sauce{saucesWithIng.length !== 1 ? "s" : ""}
                </div>
                {saucesWithIng.map(s => (
                  <div
                    key={s.id}
                    onClick={() => { setIngSearch(null); navigateTo(s.id); }}
                    style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"11px 22px", borderBottom:"1px solid #f0f5fb", cursor:"pointer", transition:"background .12s" }}
                    onMouseEnter={e => e.currentTarget.style.background = "#f5f8fd"}
                    onMouseLeave={e => e.currentTarget.style.background = ""}
                  >
                    <div>
                      <div style={{ fontFamily:"'Playfair Display',serif", fontSize:14, color:"#1a2540" }}>{s.name}</div>
                      <div style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b4c8", marginTop:2, fontStyle:"italic" }}>
                        {s.ingredients.find(i => i.name.toLowerCase().includes(ingSearch.toLowerCase()))?.name}
                      </div>
                    </div>
                    <div style={{ display:"flex", gap:8, alignItems:"center", flexShrink:0 }}>
                      <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:getDifficultyColor(s.difficulty) }}>{s.difficulty}</span>
                      <span style={{ color:"#9ab8d8", fontSize:12 }}>›</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ─── Comparison Panel ─── */}
      {showCompare && (
        <div className="overlay" onClick={() => setShowCompare(false)}>
          <div onClick={e => e.stopPropagation()} style={{ background:"#fff", width:"min(820px,100vw)", height:"100vh", overflow:"auto", boxShadow:"-8px 0 32px rgba(0,0,0,.15)", animation:"slideIn .25s", display:"flex", flexDirection:"column" }}>
            {/* Header */}
            <div style={{ padding:"18px 24px", borderBottom:"1px solid #e0e8f4", display:"flex", justifyContent:"space-between", alignItems:"center", flexShrink:0 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:18, color:"#1a3060" }}>Compare Sauces</h2>
              <button className="bk" onClick={() => setShowCompare(false)}>✕</button>
            </div>

            {/* Sauce pickers */}
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", borderBottom:"1px solid #e0e8f4", flexShrink:0 }}>
              {[compareId, compareSauce && selected !== compareId ? selected : null].map((id, col) => {
                const s = id ? SAUCES.find(x => x.id === id) : null;
                return (
                  <div key={col} style={{ padding:"14px 20px", borderRight: col===0 ? "1px solid #e0e8f4" : "none" }}>
                    {s ? (
                      <div>
                        <div style={{ fontFamily:"'Playfair Display',serif", fontSize:15, fontWeight:700, color:s.accent }}>{s.name}</div>
                        <div style={{ fontFamily:"'Crimson Text',serif", fontStyle:"italic", fontSize:12, color:"#8898b8", marginTop:2 }}>{s.tagline}</div>
                      </div>
                    ) : (
                      <div style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#a0b4c8", fontStyle:"italic" }}>
                        {col === 0 ? "Select a sauce to compare" : "No second sauce — open a sauce first"}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>

            {/* Pick sauce A from list */}
            {!compareId && (
              <div style={{ padding:"14px 20px" }}>
                <div style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b4c8", marginBottom:10, textTransform:"uppercase", letterSpacing:"1px" }}>Pick a sauce</div>
                <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                  {SAUCES.map(s => (
                    <button key={s.id} onClick={() => setCompareId(s.id)} style={{ background:"#f4f7fc", border:"1px solid #cdd8ea", color:"#3a5878", cursor:"pointer", padding:"3px 10px", borderRadius:20, fontFamily:"'Crimson Text',serif", fontSize:12, transition:"all .12s" }}
                      onMouseEnter={e => { e.currentTarget.style.background="#e4edf9"; e.currentTarget.style.borderColor="#8aaad0"; }}
                      onMouseLeave={e => { e.currentTarget.style.background="#f4f7fc"; e.currentTarget.style.borderColor="#cdd8ea"; }}
                    >{s.name}</button>
                  ))}
                </div>
              </div>
            )}

            {/* Side-by-side comparison */}
            {compareId && (() => {
              const sA = SAUCES.find(x => x.id === compareId);
              const sB = sauce ?? (selected ? SAUCES.find(x => x.id === selected) : null);
              if (!sA) return null;
              const rows = [
                { label:"Category",   a: CATEGORIES[sA.category]?.label,  b: sB ? CATEGORIES[sB.category]?.label : "—" },
                { label:"Difficulty", a: sA.difficulty,                   b: sB?.difficulty ?? "—" },
                { label:"Time",       a: sA.time,                         b: sB?.time ?? "—" },
                { label:"Steps",      a: `${sA.steps.length} steps`,       b: sB ? `${sB.steps.length} steps` : "—" },
                { label:"Ingredients",a: `${sA.ingredients.length} items`, b: sB ? `${sB.ingredients.length} items` : "—" },
                { label:"Children",   a: `${sA.children.length} daughters`,b: sB ? `${sB.children.length} daughters` : "—" },
              ];
              // shared ingredients
              const sharedIngs = sB ? sA.ingredients.filter(ia => sB.ingredients.some(ib => ib.name.toLowerCase().includes(ia.name.split(" ")[0].toLowerCase()))).map(i => i.name) : [];
              return (
                <div style={{ flex:1, overflow:"auto", padding:"0 0 24px 0" }}>
                  {/* Stats table */}
                  <div style={{ margin:"16px 20px 0 20px" }}>
                    <div style={{ fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif", letterSpacing:"1px", textTransform:"uppercase", marginBottom:8 }}>At a glance</div>
                    {rows.map((row, i) => (
                      <div key={i} style={{ display:"grid", gridTemplateColumns:"100px 1fr 1fr", borderBottom:"1px solid #f0f5fb", padding:"9px 0", alignItems:"center" }}>
                        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#8898b8", textTransform:"uppercase", letterSpacing:".5px" }}>{row.label}</span>
                        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:14, color:"#1a2540", paddingRight:12 }}>{row.a}</span>
                        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:14, color: sB ? "#1a2540" : "#c0c8d8" }}>{row.b}</span>
                      </div>
                    ))}
                  </div>

                  {/* Shared ingredients */}
                  {sharedIngs.length > 0 && (
                    <div style={{ margin:"16px 20px 0 20px", background:"#f0fbf4", border:"1px solid #a8deb8", borderRadius:8, padding:"12px 16px" }}>
                      <div style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#2a8050", textTransform:"uppercase", letterSpacing:"1px", marginBottom:8 }}>
                        Shared ingredients ({sharedIngs.length})
                      </div>
                      <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                        {sharedIngs.map(i => <span key={i} className="pill" style={{ background:"#e0f8eb", color:"#2a7040", border:"1px solid #88ccaa" }}>{i}</span>)}
                      </div>
                    </div>
                  )}

                  {/* Description comparison */}
                  <div style={{ margin:"16px 20px 0 20px", display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
                    {[sA, sB].map((s, i) => s ? (
                      <div key={i} style={{ background:"#f8fafd", border:"1px solid #dde8f4", borderRadius:8, padding:"14px" }}>
                        <div style={{ fontFamily:"'Playfair Display',serif", fontSize:13, fontWeight:700, color:s.accent, marginBottom:8 }}>{s.name}</div>
                        <p style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#5a6880", lineHeight:1.65 }}>{s.description}</p>
                        <div style={{ marginTop:10, fontFamily:"'Crimson Text',serif", fontSize:12, color:"#8898b8", fontStyle:"italic" }}>{s.tips.slice(0,120)}…</div>
                      </div>
                    ) : (
                      <div key={i} style={{ background:"#f8fafd", border:"1px dashed #dde8f4", borderRadius:8, padding:"14px", display:"flex", alignItems:"center", justifyContent:"center" }}>
                        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#b0bcd0", fontStyle:"italic" }}>Open a sauce in the encyclopedia to compare</span>
                      </div>
                    ))}
                  </div>

                  {/* Change A */}
                  <div style={{ margin:"16px 20px 0 20px" }}>
                    <div style={{ fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif", letterSpacing:"1px", textTransform:"uppercase", marginBottom:8 }}>Change comparison sauce</div>
                    <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                      {SAUCES.slice(0, 30).map(s => (
                        <button key={s.id} onClick={() => setCompareId(s.id)} style={{ background: s.id===compareId ? "#e4edf9" : "#f4f7fc", border:`1px solid ${s.id===compareId ? "#4878c0" : "#cdd8ea"}`, color: s.id===compareId ? "#2060b0" : "#3a5878", cursor:"pointer", padding:"2px 8px", borderRadius:20, fontFamily:"'Crimson Text',serif", fontSize:11, transition:"all .12s" }}>
                          {s.name}
                        </button>
                      ))}
                      <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", alignSelf:"center" }}>…and more</span>
                    </div>
                  </div>
                </div>
              );
            })()}
          </div>
        </div>
      )}

      {/* ─── Cooking Mode Overlay ─── */}
      {cookingMode && sauce && (
        <div style={{ position:"fixed", inset:0, background:"#0c1828", zIndex:300, display:"flex", flexDirection:"column", animation:"fadeIn .25s" }}>
          {/* Top bar */}
          <div style={{ padding:"14px 24px", borderBottom:"1px solid #1e3050", display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
            <div>
              <div style={{ fontFamily:"'Playfair Display',serif", fontStyle:"italic", color:"#6090d0", fontSize:13 }}>{sauce.name}</div>
              <div style={{ fontFamily:"'Crimson Text',serif", color:"#8aa8c8", fontSize:12, marginTop:2 }}>
                Step {cookStep+1} of {sauce.steps.length} · Press Space to complete · ← → to navigate · Esc to exit
              </div>
            </div>
            <div style={{ display:"flex", gap:8, alignItems:"center" }}>
              {/* Progress dots */}
              <div style={{ display:"flex", gap:6 }}>
                {sauce.steps.map((_, i) => {
                  const done = completedSteps[`${sauce.id}_${i}`];
                  return (
                    <div key={i} onClick={() => setCookStep(i)} style={{ width: i===cookStep?20:8, height:8, borderRadius:4, background: done ? "#5ab870" : i===cookStep ? "#4878c0" : "#1e3050", cursor:"pointer", transition:"all .2s", flexShrink:0 }} />
                  );
                })}
              </div>
              <button onClick={() => setCookingMode(false)} style={{ background:"none", border:"1px solid #2a4060", color:"#7090b0", cursor:"pointer", borderRadius:6, padding:"5px 12px", fontFamily:"'Crimson Text',serif", fontSize:13 }}>Exit</button>
            </div>
          </div>

          {/* Step content */}
          <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:"40px 24px", textAlign:"center" }}>
            {(() => {
              const step = sauce.steps[cookStep];
              const done = completedSteps[`${sauce.id}_${cookStep}`];
              const suggestedMins = extractStepTime(step.body);
              const totalSecs = suggestedMins ? suggestedMins * 60 : null;
              const remaining = timerSecs ?? totalSecs;
              const progress = totalSecs && remaining !== null ? Math.max(0, remaining / totalSecs) : 0;
              const minsLeft = remaining !== null ? Math.floor(remaining / 60) : 0;
              const secsLeft = remaining !== null ? remaining % 60 : 0;
              const circumference = 2 * Math.PI * 44;
              return (
                <>
                  <div style={{ fontFamily:"'Crimson Text',serif", color:"#3a6090", fontSize:13, textTransform:"uppercase", letterSpacing:"2px", marginBottom:12 }}>Step {cookStep+1}</div>
                  <div style={{ fontFamily:"'Playfair Display',serif", fontSize:28, fontWeight:700, color: done ? "#5ab870" : "#d0e4f8", marginBottom:20, maxWidth:600, lineHeight:1.2, transition:"color .3s" }}>{step.title}</div>
                  <div style={{ fontFamily:"'Crimson Text',serif", fontSize:18, color: done ? "#4a9060" : "#7a9cc0", maxWidth:560, lineHeight:1.75, transition:"color .3s", marginBottom:28 }}>{step.body}</div>

                  {/* Timer */}
                  {suggestedMins && (
                    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:12, marginBottom:24, background:"rgba(255,255,255,.04)", border:"1px solid #1e3050", borderRadius:16, padding:"20px 32px" }}>
                      <div style={{ position:"relative", width:100, height:100 }}>
                        <svg width="100" height="100" style={{ transform:"rotate(-90deg)" }}>
                          <circle cx="50" cy="50" r="44" fill="none" stroke="#1e3050" strokeWidth="6"/>
                          <circle cx="50" cy="50" r="44" fill="none" stroke={timerDone ? "#5ab870" : "#4878c0"} strokeWidth="6"
                            strokeDasharray={circumference} strokeDashoffset={circumference * (1 - progress)}
                            style={{ transition:"stroke-dashoffset .5s, stroke .3s" }}
                          />
                        </svg>
                        <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center" }}>
                          {timerDone ? (
                            <span style={{ fontSize:28, color:"#5ab870" }}>✓</span>
                          ) : (
                            <>
                              <span style={{ fontFamily:"'Playfair Display',serif", fontSize:20, color:"#d0e4f8", lineHeight:1 }}>{minsLeft}:{String(secsLeft).padStart(2,"0")}</span>
                              <span style={{ fontFamily:"'Crimson Text',serif", fontSize:10, color:"#3a6090", textTransform:"uppercase", letterSpacing:"1px" }}>left</span>
                            </>
                          )}
                        </div>
                      </div>
                      <div style={{ fontFamily:"'Crimson Text',serif", color:"#4a7090", fontSize:13 }}>
                        Suggested: {suggestedMins} min{suggestedMins !== 1 ? "s" : ""}
                      </div>
                      <div style={{ display:"flex", gap:8 }}>
                        {timerSecs === null ? (
                          <button onClick={() => startTimer(suggestedMins)} style={{ background:"#1a3a5a", border:"1px solid #2a5080", color:"#80b0e0", cursor:"pointer", borderRadius:6, padding:"6px 18px", fontFamily:"'Crimson Text',serif", fontSize:14 }}>▶ Start Timer</button>
                        ) : (
                          <>
                            <button onClick={pauseTimer} style={{ background:"#1a3050", border:"1px solid #2a4a70", color:"#70a0c8", cursor:"pointer", borderRadius:6, padding:"6px 14px", fontFamily:"'Crimson Text',serif", fontSize:13 }}>
                              {timerRunning ? "⏸ Pause" : "▶ Resume"}
                            </button>
                            <button onClick={() => resetTimer(suggestedMins)} style={{ background:"none", border:"1px solid #1e3050", color:"#506070", cursor:"pointer", borderRadius:6, padding:"6px 14px", fontFamily:"'Crimson Text',serif", fontSize:13 }}>↺ Reset</button>
                          </>
                        )}
                      </div>
                      {timerDone && <div style={{ fontFamily:"'Crimson Text',serif", color:"#5ab870", fontSize:14, fontStyle:"italic" }}>Time's up! Check your {step.title.toLowerCase()}.</div>}
                    </div>
                  )}

                  <button
                    onClick={() => { toggleStep(sauce.id, cookStep); if (!done && cookStep < sauce.steps.length - 1) setCookStep(s => s + 1); }}
                    style={{ background: done ? "#1e4030" : "#1a2e50", border:"1px solid", borderColor: done ? "#3a8058" : "#2a4a80", color: done ? "#5ab870" : "#4878c0", cursor:"pointer", borderRadius:8, padding:"12px 32px", fontFamily:"'Crimson Text',serif", fontSize:16, transition:"all .25s", minWidth:180 }}
                  >
                    {done ? "✓ Completed · Next →" : "Mark Complete & Continue →"}
                  </button>
                </>
              );
            })()}
          </div>

          {/* Bottom nav */}
          <div style={{ padding:"20px 24px", borderTop:"1px solid #1e3050", display:"flex", justifyContent:"space-between", flexShrink:0 }}>
            <button
              disabled={cookStep === 0}
              onClick={() => setCookStep(s => s - 1)}
              style={{ background:"none", border:"1px solid #1e3050", color: cookStep===0 ? "#2a3848" : "#6090b8", cursor: cookStep===0 ? "default":"pointer", borderRadius:8, padding:"10px 24px", fontFamily:"'Crimson Text',serif", fontSize:15, transition:"all .2s" }}
            >
              ← Previous
            </button>
            <div style={{ fontFamily:"'Crimson Text',serif", color:"#3a6090", fontSize:13, alignSelf:"center" }}>
              {sauce.steps.filter((_, i) => completedSteps[`${sauce.id}_${i}`]).length} / {sauce.steps.length} completed
            </div>
            {cookStep < sauce.steps.length - 1 ? (
              <button onClick={() => setCookStep(s => s + 1)} style={{ background:"#1a2e50", border:"1px solid #2a4a80", color:"#4878c0", cursor:"pointer", borderRadius:8, padding:"10px 24px", fontFamily:"'Crimson Text',serif", fontSize:15, transition:"all .2s" }}>
                Next →
              </button>
            ) : (
              <button onClick={() => setCookingMode(false)} style={{ background:"#1e4030", border:"1px solid #3a8058", color:"#5ab870", cursor:"pointer", borderRadius:8, padding:"10px 24px", fontFamily:"'Crimson Text',serif", fontSize:15 }}>
                ✓ Finish
              </button>
            )}
          </div>
        </div>
      )}

      {/* ─── Family Tree ─── */}
      {showTree && (
        <div style={{ background:"#fff", borderBottom:"1px solid #cdd8ea", padding:"20px", animation:"fadeIn .2s" }}>
          <div style={{ maxWidth:980, margin:"0 auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:16, color:"#1a3060", fontStyle:"italic" }}>The French Sauce Family Tree</h2>
              <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b4c8" }}>Click any sauce to open it</span>
            </div>
            <div style={{ overflowX:"auto" }}>
              {SAUCES.filter(s => s.category === "mother").map(mother => {
                const children = SAUCES.filter(s => s.parent === mother.id);
                const grandchildren = children.flatMap(c => SAUCES.filter(s => s.parent === c.id));
                return (
                  <div key={mother.id} style={{ marginBottom:28 }}>
                    {/* Mother sauce */}
                    <div style={{ display:"flex", alignItems:"flex-start", gap:0 }}>
                      <div style={{ display:"flex", flexDirection:"column", alignItems:"center", flexShrink:0 }}>
                        <div
                          onClick={() => { navigateTo(mother.id); setShowTree(false); }}
                          style={{ background:`linear-gradient(135deg,${mother.accent}20,${mother.accent}10)`, border:`2px solid ${mother.accent}`, borderRadius:8, padding:"6px 14px", cursor:"pointer", fontFamily:"'Playfair Display',serif", fontSize:13, fontWeight:700, color:mother.accent, whiteSpace:"nowrap", transition:"all .15s" }}
                          onMouseEnter={e => e.currentTarget.style.background = `${mother.accent}30`}
                          onMouseLeave={e => e.currentTarget.style.background = `linear-gradient(135deg,${mother.accent}20,${mother.accent}10)`}
                        >
                          👑 {mother.name}
                        </div>
                        {children.length > 0 && <div style={{ width:2, height:16, background:`${mother.accent}60` }} />}
                      </div>

                      {/* Children row */}
                      {children.length > 0 && (
                        <div style={{ display:"flex", flexWrap:"wrap", gap:6, paddingLeft:8, paddingTop:4 }}>
                          {children.map(child => {
                            const gcs = SAUCES.filter(s => s.parent === child.id);
                            return (
                              <div key={child.id} style={{ display:"flex", flexDirection:"column", alignItems:"center" }}>
                                <div
                                  onClick={() => { navigateTo(child.id); setShowTree(false); }}
                                  style={{ background:`${child.accent}12`, border:`1.5px solid ${child.accent}80`, borderRadius:6, padding:"4px 10px", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontSize:12, color:child.accent, whiteSpace:"nowrap", transition:"all .15s" }}
                                  onMouseEnter={e => e.currentTarget.style.background = `${child.accent}25`}
                                  onMouseLeave={e => e.currentTarget.style.background = `${child.accent}12`}
                                >
                                  {child.name}
                                </div>
                                {gcs.length > 0 && (
                                  <>
                                    <div style={{ width:1, height:10, background:"#c8d8ea" }} />
                                    <div style={{ display:"flex", gap:4, flexWrap:"wrap", justifyContent:"center" }}>
                                      {gcs.map(gc => (
                                        <div
                                          key={gc.id}
                                          onClick={() => { navigateTo(gc.id); setShowTree(false); }}
                                          style={{ background:"#f4f7fc", border:"1px solid #cdd8ea", borderRadius:4, padding:"2px 7px", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontSize:11, color:"#4a6888", whiteSpace:"nowrap", transition:"all .15s" }}
                                          onMouseEnter={e => { e.currentTarget.style.background = "#e4edf9"; e.currentTarget.style.borderColor = "#8aaad0"; }}
                                          onMouseLeave={e => { e.currentTarget.style.background = "#f4f7fc"; e.currentTarget.style.borderColor = "#cdd8ea"; }}
                                        >
                                          {gc.name}
                                        </div>
                                      ))}
                                    </div>
                                  </>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* ─── Detail View ─── */}
      {sauce && (
        <div style={{ maxWidth:740, margin:"0 auto", padding:"24px 16px", animation:"fadeIn .18s" }}>
          {/* Ancestry breadcrumb */}
          {(() => {
            const ancestors = getAncestry(sauce);
            return ancestors.length > 0 ? (
              <div style={{ display:"flex", alignItems:"center", gap:5, marginBottom:12, flexWrap:"wrap" }}>
                {ancestors.map((a, i) => (
                  <span key={a.id} style={{ display:"flex", alignItems:"center", gap:5 }}>
                    <span onClick={() => navigateTo(a.id)} style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#6a88b8", cursor:"pointer", textDecoration:"underline", textDecorationColor:"#b0c8e4", textUnderlineOffset:2 }}>{a.name}</span>
                    <span style={{ color:"#c0cfe0", fontSize:11 }}>›</span>
                  </span>
                ))}
                <span style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#1a3060", fontWeight:600 }}>{sauce.name}</span>
              </div>
            ) : null;
          })()}
          {/* Hero */}
          <div style={{ background:"#fff", border:"1px solid #cdd8ea", borderRadius:12, padding:"22px 24px", marginBottom:18, position:"relative", overflow:"hidden" }}>
            <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:`linear-gradient(90deg,${sauce.accent} 0%,${sauce.accent}44 70%,transparent 100%)` }} />

            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:10 }}>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ display:"flex", gap:5, marginBottom:8, flexWrap:"wrap", alignItems:"center" }}>
                  <span className="pill" style={{ background:"#e4edf9", color:"#2060b0", border:"1px solid #b8d0ef" }}>{CATEGORIES[sauce.category]?.label}</span>
                  {sauce.parent && (
                    <span className="pill" style={{ background:"#e4f4fb", color:"#1870a0", border:"1px solid #a8d8ee", cursor:"pointer" }} onClick={() => navigateTo(sauce.parent)}>
                      ↑ {SAUCES.find(s => s.id === sauce.parent)?.name}
                    </span>
                  )}
                  <span className="pill" style={{ background: getDifficultyColor(sauce.difficulty)+"18", color: getDifficultyColor(sauce.difficulty), border:`1px solid ${getDifficultyColor(sauce.difficulty)}44` }}>{sauce.difficulty}</span>
                </div>
                <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, fontWeight:700, color:"#1a2540", lineHeight:1.1, marginBottom:4 }}>{sauce.name}</h2>
                <p style={{ fontFamily:"'Playfair Display',serif", fontStyle:"italic", color:sauce.accent, fontSize:14 }}>{sauce.tagline}</p>
              </div>

              <div style={{ display:"flex", gap:10, flexShrink:0, alignItems:"center", flexWrap:"wrap", justifyContent:"flex-end" }}>
                {/* Star rating */}
                <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:2 }}>
                  <div style={{ display:"flex", gap:1 }}>
                    {[1,2,3,4,5].map(star => (
                      <button
                        key={star}
                        className="star-btn"
                        title={`Rate ${star} star${star>1?"s":""}`}
                        onClick={() => ratesSauce(sauce.id, star)}
                        style={{ color: star <= (ratings[sauce.id]||0) ? "#f0b030" : "#c0c8d8" }}
                      >{star <= (ratings[sauce.id]||0) ? "★" : "☆"}</button>
                    ))}
                  </div>
                  {ratings[sauce.id] && <span style={{ fontFamily:"'Crimson Text',serif", fontSize:10, color:"#a0b4c8" }}>{["","Poor","Fair","Good","Great","Perfect"][ratings[sauce.id]]}</span>}
                </div>
                <div style={{ textAlign:"center" }}>
                  <div style={{ fontSize:10, color:"#a0b4c8", textTransform:"uppercase", letterSpacing:"1px", fontFamily:"'Crimson Text',serif" }}>Time</div>
                  <div style={{ color:"#1a2540", fontSize:14, fontFamily:"'Crimson Text',serif" }}>{sauce.time}</div>
                </div>
                <button
                  onClick={(e) => toggleFav(sauce.id, e)}
                  title={favorites.has(sauce.id) ? "Remove from favourites" : "Save to favourites"}
                  style={{ background:"none", border:"1px solid", borderColor: favorites.has(sauce.id) ? "#e05070" : "#cdd8ea", borderRadius:8, padding:"6px 10px", cursor:"pointer", fontSize:18, transition:"all .15s", color: favorites.has(sauce.id) ? "#e05070" : "#c0c8d8" }}
                >
                  {favorites.has(sauce.id) ? "♥" : "♡"}
                </button>
                <button
                  onClick={(e) => toggleShop(sauce.id, e)}
                  title={shopList.has(sauce.id) ? "Remove from shopping list" : "Add to shopping list"}
                  style={{ background: shopList.has(sauce.id) ? "#e4edf9" : "none", border:"1px solid", borderColor: shopList.has(sauce.id) ? "#4878c0" : "#cdd8ea", borderRadius:8, padding:"6px 10px", cursor:"pointer", fontSize:13, transition:"all .15s", color: shopList.has(sauce.id) ? "#2060b0" : "#a0b0c8", fontFamily:"'Crimson Text',serif" }}
                >
                  {shopList.has(sauce.id) ? "🛒 Added" : "+ List"}
                </button>
                <button
                  onClick={() => { setCompareId(sauce.id); setShowCompare(true); }}
                  title="Compare with another sauce"
                  style={{ background:"none", border:"1px solid #cdd8ea", borderRadius:8, padding:"6px 10px", cursor:"pointer", fontSize:13, transition:"all .15s", color:"#a0b0c8", fontFamily:"'Crimson Text',serif" }}
                >
                  ⇌ Compare
                </button>
                <button
                  onClick={() => window.print()}
                  title="Print this recipe"
                  style={{ background:"none", border:"1px solid #cdd8ea", borderRadius:8, padding:"6px 10px", cursor:"pointer", fontSize:13, transition:"all .15s", color:"#a0b0c8", fontFamily:"'Crimson Text',serif" }}
                >
                  🖨 Print
                </button>
              </div>
            </div>

            <p style={{ fontFamily:"'Crimson Text',serif", fontSize:15, color:"#5a6880", marginTop:12, lineHeight:1.7 }}>{sauce.description}</p>

            <div style={{ marginTop:12, display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
              <span style={{ fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif" }}>Pairs with:</span>
              {sauce.pairings.map(p => <span key={p} className="pill" style={{ background:"#f0f4fa", color:"#3a6090", border:"1px solid #c8d8ec" }}>{p}</span>)}
            </div>

            {/* Technique tags */}
            {(() => {
              const techs = getSauceTechniques(sauce);
              return techs.length > 0 ? (
                <div style={{ marginTop:10, display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
                  <span style={{ fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif" }}>Techniques:</span>
                  {techs.map(t => (
                    <span key={t} className="pill" style={{ background:"#f8f2ff", color:"#7050a8", border:"1px solid #d8c8f0", cursor:"pointer" }} onClick={() => { setTechFilter(t); setSelected(null); }}>
                      {t.replace("_tech","").replace(/_/g," ")}
                    </span>
                  ))}
                </div>
              ) : null;
            })()}

            {sauce.children.length > 0 && (
              <div style={{ marginTop:12, paddingTop:12, borderTop:"1px solid #e8f0f8" }}>
                <span style={{ fontSize:11, color:"#a0b4c8", fontFamily:"'Crimson Text',serif", marginRight:6 }}>Daughter sauces:</span>
                {sauce.children.map(cid => { const c = SAUCES.find(s => s.id === cid); return c ? <span key={cid} className="ctag" onClick={() => navigateTo(cid)}>→ {c.name}</span> : null; })}
              </div>
            )}
          </div>

          {/* Tabs */}
          <div style={{ borderBottom:"1px solid #cdd8ea", marginBottom:18, display:"flex", alignItems:"center" }}>
            <div style={{ flex:1, display:"flex" }}>
            {["ingredients","method","notes"].map(t => (
              <button key={t} className={`tb ${activeTab===t?"on":""}`} onClick={() => setActiveTab(t)}>
                {t.charAt(0).toUpperCase()+t.slice(1)}
                {t === "notes" && userNotes[sauce.id] && <span style={{ marginLeft:5, fontSize:9, color:"#d4b84a" }}>●</span>}
                {t === "method" && cookedIds.has(sauce.id) && <span style={{ marginLeft:5, fontSize:9, color:"#5ab870" }}>✓</span>}
              </button>
            ))}
            </div>
            <button
              onClick={startCooking}
              title="Enter step-by-step cooking mode"
              style={{ background:"linear-gradient(135deg,#1a4a90,#2060b0)", border:"none", color:"#fff", cursor:"pointer", borderRadius:6, padding:"6px 14px", fontFamily:"'Crimson Text',serif", fontSize:13, marginRight:2, display:"flex", alignItems:"center", gap:6, flexShrink:0, boxShadow:"0 2px 8px rgba(30,70,160,.2)" }}
            >
              👨‍🍳 Cook
            </button>
          </div>

          {/* Ingredients */}
          {activeTab === "ingredients" && (
            <div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14, flexWrap:"wrap", gap:12 }}>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:16, color:"#1a3060", fontStyle:"italic" }}>Ingredients</h3>
                <div style={{ display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
                  {/* Metric/Imperial */}
                  <div style={{ display:"flex", gap:2, background:"#eef2f8", borderRadius:20, padding:3 }}>
                    {[["Metric", false],["Imperial", true]].map(([label, val]) => (
                      <button key={label} onClick={() => setIsImperial(val)} style={{ background: isImperial===val ? "#fff" : "transparent", border: isImperial===val ? "1px solid #cdd8ea" : "1px solid transparent", color: isImperial===val ? "#2060b0" : "#8898b0", cursor:"pointer", padding:"4px 12px", borderRadius:16, fontFamily:"'Crimson Text',serif", fontSize:13, transition:"all .15s" }}>{label}</button>
                    ))}
                  </div>
                  {/* Servings */}
                  <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                    <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b4c8" }}>Serves</span>
                    <button className="mb" disabled={curServings <= 1} onClick={() => setServings(Math.max(1, curServings-1))}>−</button>
                    <span style={{ fontFamily:"'Playfair Display',serif", fontSize:17, color:"#2060b0", minWidth:24, textAlign:"center" }}>{curServings}</span>
                    <button className="mb" disabled={curServings >= 24} onClick={() => setServings(Math.min(24, curServings+1))}>+</button>
                    {servings !== null && servings !== baseServings && (
                      <button onClick={() => setServings(null)} style={{ background:"none", border:"none", color:"#b0b8c8", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontSize:12 }}>↺</button>
                    )}
                  </div>
                </div>
              </div>
              {scale !== 1 && (
                <div style={{ background:"#e8f4fb", border:"1px solid #a8d4ec", borderRadius:6, padding:"7px 14px", marginBottom:12, fontFamily:"'Crimson Text',serif", fontSize:13, color:"#2070a8" }}>
                  Scaled ×{formatNum(scale)} · base recipe serves {baseServings}
                </div>
              )}
              <div style={{ background:"#fff", border:"1px solid #cdd8ea", borderRadius:10, overflow:"hidden" }}>
                {sauce.ingredients.map((ing, i) => (
                  <div
                    key={i}
                    style={{ display:"flex", justifyContent:"space-between", padding:"11px 18px", borderBottom: i < sauce.ingredients.length-1 ? "1px solid #edf2f9":"none", alignItems:"center", transition:"background .1s", cursor:"pointer" }}
                    onClick={() => setIngSearch(ing.name)}
                    title={`Find all sauces using ${ing.name}`}
                    onMouseEnter={e => e.currentTarget.style.background = "#f7f9fd"}
                    onMouseLeave={e => e.currentTarget.style.background = ""}
                  >
                    <span style={{ fontFamily:"'Crimson Text',serif", fontSize:16, color:"#1a2540" }}>{ing.name}</span>
                    <span style={{ fontFamily:"'Crimson Text',serif", fontSize:15, color:"#2060b0", fontWeight:600, minWidth:90, textAlign:"right", flexShrink:0, marginLeft:12 }}>
                      {formatAmount(ing.value * scale, ing.unit, isImperial)}
                    </span>
                  </div>
                ))}
              </div>
              <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#c0d0e0", marginTop:8, fontStyle:"italic" }}>
                {isImperial ? "Weights in oz · volumes in fl oz" : "Weights in g · volumes in ml"} · Counts unchanged · Click an ingredient to find other sauces using it
              </p>
            </div>
          )}

          {/* Method */}
          {activeTab === "method" && (
            <div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:16, color:"#1a3060", fontStyle:"italic" }}>Method</h3>
                <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                  {Object.keys(completedSteps).some(k => k.startsWith(sauce.id+"_")) && (
                    <button onClick={() => clearSteps(sauce.id)} style={{ background:"none", border:"none", color:"#b0b8c8", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontSize:12 }}>↺ Reset</button>
                  )}
                  <button onClick={startCooking} style={{ background:"#e8f0fb", border:"1px solid #b0ccee", color:"#2060b0", cursor:"pointer", borderRadius:6, padding:"5px 13px", fontFamily:"'Crimson Text',serif", fontSize:13, display:"flex", alignItems:"center", gap:5 }}>
                    👨‍🍳 Cooking mode
                  </button>
                </div>
              </div>
              {sauce.steps.map((step, i) => {
                const done = completedSteps[`${sauce.id}_${i}`];
                return (
                  <div
                    key={i}
                    onClick={() => toggleStep(sauce.id, i)}
                    style={{ display:"flex", gap:14, marginBottom:14, cursor:"pointer", background: done ? "#f2fbf4" : "#fff", border:"1px solid", borderColor: done ? "#a8deb8" : "#e0e8f4", borderRadius:10, padding:"14px 16px", transition:"all .2s", alignItems:"flex-start" }}
                  >
                    <div style={{ width:28, height:28, borderRadius:"50%", background: done ? "linear-gradient(135deg,#5ab870,#3a9858)" : "linear-gradient(135deg,#e4edf9,#c8dcf4)", border:"1px solid", borderColor: done ? "#3a9858" : "#9ab8e0", display:"flex", alignItems:"center", justifyContent:"center", fontSize: done ? 15 : 12, color: done ? "#fff" : "#2060b0", flexShrink:0, fontFamily:"'Crimson Text',serif", fontWeight:600, transition:"all .25s" }}>
                      {done ? "✓" : i+1}
                    </div>
                    <div style={{ flex:1 }}>
                      <div style={{ fontFamily:"'Playfair Display',serif", fontSize:14, color: done ? "#2a7040" : "#1a2540", marginBottom:5, textDecoration: done ? "line-through" : "none", transition:"all .2s" }}>{step.title}</div>
                      <div style={{ fontFamily:"'Crimson Text',serif", fontSize:15, color: done ? "#6aaa80" : "#5a6880", lineHeight:1.7, transition:"color .2s" }}>{step.body}</div>
                    </div>
                  </div>
                );
              })}
              {sauce.steps.every((_, i) => completedSteps[`${sauce.id}_${i}`]) && (
                <div style={{ textAlign:"center", padding:"18px", background:"#f0fbf4", border:"1px solid #a8deb8", borderRadius:10, fontFamily:"'Playfair Display',serif", fontSize:15, color:"#2a7040", fontStyle:"italic" }}>
                  ✓ All steps complete · Bon appétit!
                </div>
              )}
              <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#c0d0e0", marginTop:10, fontStyle:"italic" }}>Click a step to mark it complete</p>
            </div>
          )}

          {/* Notes */}
          {activeTab === "notes" && (
            <div>
              <div style={{ background:"#f8fafd", border:"1px solid #cdd8ea", borderRadius:10, padding:"22px 24px", borderLeft:"4px solid "+sauce.accent, marginBottom:20 }}>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:16, color:"#1a3060", marginBottom:12, fontStyle:"italic" }}>Chef's Notes</h3>
                <p style={{ fontFamily:"'Crimson Text',serif", fontSize:16, color:"#5a6880", lineHeight:1.8 }}>{sauce.tips}</p>
              </div>

              {/* Personal notes */}
              <div style={{ background:"#fffdf5", border:"1px solid #e8dca8", borderRadius:10, padding:"20px 22px", borderLeft:"4px solid #d4b84a" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
                  <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:15, color:"#7a6020", fontStyle:"italic" }}>My Notes</h3>
                  {!editingNote ? (
                    <button onClick={() => openNote(sauce.id)} style={{ background:"none", border:"1px solid #d4b84a", color:"#8a7030", cursor:"pointer", borderRadius:6, padding:"4px 12px", fontFamily:"'Crimson Text',serif", fontSize:13, transition:"all .15s" }}>
                      {userNotes[sauce.id] ? "✏️ Edit" : "+ Add note"}
                    </button>
                  ) : (
                    <div style={{ display:"flex", gap:6 }}>
                      {userNotes[sauce.id] && <button onClick={() => deleteNote(sauce.id)} style={{ background:"none", border:"none", color:"#c08888", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontSize:13 }}>Delete</button>}
                      <button onClick={() => setEditingNote(false)} style={{ background:"none", border:"1px solid #d0c8b0", color:"#a09060", cursor:"pointer", borderRadius:6, padding:"4px 10px", fontFamily:"'Crimson Text',serif", fontSize:13 }}>Cancel</button>
                      <button onClick={() => saveNote(sauce.id)} style={{ background:"#d4b84a", border:"none", color:"#fff", cursor:"pointer", borderRadius:6, padding:"4px 12px", fontFamily:"'Crimson Text',serif", fontSize:13 }}>Save</button>
                    </div>
                  )}
                </div>
                {editingNote ? (
                  <textarea
                    ref={noteRef}
                    value={noteText}
                    onChange={e => setNoteText(e.target.value)}
                    placeholder="Add your own notes, substitutions, timings, observations…"
                    style={{ width:"100%", minHeight:100, background:"#fffef8", border:"1px solid #d4c870", borderRadius:6, padding:"10px 12px", fontFamily:"'Crimson Text',serif", fontSize:15, color:"#5a4a20", lineHeight:1.65, resize:"vertical", outline:"none" }}
                  />
                ) : userNotes[sauce.id] ? (
                  <p style={{ fontFamily:"'Crimson Text',serif", fontSize:15, color:"#6a5820", lineHeight:1.75, whiteSpace:"pre-wrap" }}>{userNotes[sauce.id]}</p>
                ) : (
                  <p style={{ fontFamily:"'Crimson Text',serif", fontSize:14, color:"#c8b870", fontStyle:"italic" }}>No personal notes yet. Click "Add note" to record your own observations.</p>
                )}
              </div>
            </div>
          )}

          {/* Related sauces */}
          {(() => {
            const parent = sauce.parent ? SAUCES.find(s => s.id === sauce.parent) : null;
            const siblings = sauce.parent ? SAUCES.filter(s => s.parent === sauce.parent && s.id !== sauce.id) : [];
            const children = SAUCES.filter(s => s.parent === sauce.id);
            if (!parent && siblings.length === 0 && children.length === 0) return null;
            return (
              <div style={{ marginTop:24, paddingTop:18, borderTop:"1px solid #e0e8f4" }}>
                <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", letterSpacing:"1px", textTransform:"uppercase", marginBottom:12 }}>Related sauces</p>
                {parent && (
                  <div style={{ marginBottom:10 }}>
                    <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#a0b4c8", marginBottom:6 }}>Parent sauce</p>
                    <div className="tn" style={{ fontSize:12, borderColor: parent.accent+"66", color: parent.accent, display:"inline-flex", alignItems:"center", gap:4 }} onClick={() => navigateTo(parent.id)}>
                      👑 {parent.name}
                    </div>
                  </div>
                )}
                {siblings.length > 0 && (
                  <div style={{ marginBottom:10 }}>
                    <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#a0b4c8", marginBottom:6 }}>Sibling sauces ({siblings.length})</p>
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                      {siblings.map(s => (
                        <div key={s.id} className="tn" style={{ fontSize:12, borderColor: s.accent+"66", color: s.accent }} onClick={() => navigateTo(s.id)}>{s.name}</div>
                      ))}
                    </div>
                  </div>
                )}
                {children.length > 0 && (
                  <div>
                    <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#a0b4c8", marginBottom:6 }}>Daughter sauces ({children.length})</p>
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                      {children.map(s => (
                        <div key={s.id} className="tn" style={{ fontSize:12, borderColor: s.accent+"66", color: s.accent }} onClick={() => navigateTo(s.id)}>{s.name}</div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })()}

          {/* Recently viewed */}
          {recentlyViewed.filter(id => id !== selected).length > 0 && (
            <div style={{ marginTop:28, paddingTop:18, borderTop:"1px solid #e0e8f4" }}>
              <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", letterSpacing:"1px", textTransform:"uppercase", marginBottom:10 }}>Recently viewed</p>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                {recentlyViewed.filter(id => id !== selected).map(id => {
                  const s = SAUCES.find(x => x.id === id);
                  return s ? <div key={id} className="tn" style={{ fontSize:12, borderColor: s.accent+"66", color: s.accent }} onClick={() => navigateTo(id)}>{s.name}</div> : null;
                })}
              </div>
            </div>
          )}
        </div>
      )}

      {/* ─── List View ─── */}
      {!sauce && !showTree && (
        <div style={{ maxWidth:980, margin:"0 auto", padding:"20px 16px" }}>

          {/* Stats dashboard — only show on home (all, no search, no filter) */}
          {catFilter === "all" && !search && diffFilter === "all" && techFilter === "all" && (
            <>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))", gap:10, marginBottom:16 }}>
              {[
                { label:"Recipes",    value:SAUCES.length,             color:"#2060b0", icon:"📖" },
                { label:"Cooked",     value:cookedIds.size,            color:"#2a9858", icon:"✓" },
                { label:"Saved",      value:favorites.size,            color:"#d04060", icon:"♥" },
                { label:"In list",    value:shopList.size,             color:"#c07020", icon:"🛒" },
                { label:"With notes", value:Object.keys(userNotes).filter(id => userNotes[id]?.trim()).length, color:"#8a6020", icon:"✏️" },
                { label:"Rated",      value:Object.keys(ratings).length,                      color:"#b07010", icon:"⭐" },
                { label:"Mother",     value:SAUCES.filter(s=>s.category==="mother").length,   color:"#1a4a90", icon:"👑" },
              ].map(stat => (
                <div key={stat.label} style={{ background:"#fff", border:"1px solid #dde8f4", borderRadius:10, padding:"14px 16px", textAlign:"center" }}>
                  <div style={{ fontSize:20, marginBottom:4 }}>{stat.icon}</div>
                  <div style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:stat.color, lineHeight:1 }}>{stat.value}</div>
                  <div style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b0c8", marginTop:4 }}>{stat.label}</div>
                </div>
              ))}
            </div>

            {/* Cooking progress bar */}
            {cookedIds.size > 0 && (
              <div style={{ marginBottom:16, background:"#fff", border:"1px solid #dde8f4", borderRadius:10, padding:"14px 18px" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", marginBottom:8 }}>
                  <span style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#5a7080" }}>Cooking journey</span>
                  <span style={{ fontFamily:"'Playfair Display',serif", fontSize:13, color:"#2a9858", fontWeight:600 }}>
                    {cookedIds.size} / {SAUCES.length} — {Math.round(cookedIds.size / SAUCES.length * 100)}%
                  </span>
                </div>
                <div style={{ height:8, background:"#e8f0f8", borderRadius:4, overflow:"hidden" }}>
                  <div style={{ height:"100%", width:`${cookedIds.size / SAUCES.length * 100}%`, background:"linear-gradient(90deg,#7dd898,#2a9858)", borderRadius:4, transition:"width .5s ease" }} />
                </div>
                {cookedIds.size >= SAUCES.length && (
                  <div style={{ marginTop:8, fontFamily:"'Playfair Display',serif", fontStyle:"italic", fontSize:13, color:"#2a9858", textAlign:"center" }}>
                    👑 Maître Saucier — all recipes completed!
                  </div>
                )}
              </div>
            )}

            {/* Achievements trophy case */}
            {achievements.length > 0 && (
              <div style={{ marginBottom:16, background:"#fff", border:"1px solid #dde8f4", borderRadius:10, padding:"14px 18px" }}>
                <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", letterSpacing:"1px", textTransform:"uppercase", marginBottom:10 }}>
                  Achievements · {achievements.length} / {ACHIEVEMENTS.length}
                </p>
                <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                  {ACHIEVEMENTS.map(a => {
                    const unlocked = achievements.includes(a.id);
                    return (
                      <div key={a.id} title={a.desc} style={{ display:"flex", alignItems:"center", gap:5, background: unlocked ? "#f0f6ff" : "#f8f9fc", border:`1px solid ${unlocked ? "#b8d0ef" : "#e0e8f4"}`, borderRadius:8, padding:"5px 10px", opacity: unlocked ? 1 : 0.4, transition:"all .2s" }}>
                        <span style={{ fontSize:16, filter: unlocked ? "none" : "grayscale(1)" }}>{a.icon}</span>
                        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color: unlocked ? "#2060b0" : "#a0b0c8" }}>{a.label}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Sauce of the Day */}
            <div
              onClick={() => navigateTo(sauceOfDay.id)}
              style={{ background:`linear-gradient(135deg,${sauceOfDay.accent}18 0%,#fff 60%)`, border:`1px solid ${sauceOfDay.accent}44`, borderRadius:12, padding:"16px 20px", marginBottom:24, cursor:"pointer", display:"flex", alignItems:"center", gap:16, position:"relative", overflow:"hidden", transition:"all .2s" }}
              onMouseEnter={e => e.currentTarget.style.boxShadow = `0 4px 20px ${sauceOfDay.accent}30`}
              onMouseLeave={e => e.currentTarget.style.boxShadow = "none"}
            >
              <div style={{ position:"absolute", top:0, left:0, bottom:0, width:4, background:sauceOfDay.accent, borderRadius:"12px 0 0 12px" }} />
              <div style={{ paddingLeft:8, flex:1, minWidth:0 }}>
                <div style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:sauceOfDay.accent, textTransform:"uppercase", letterSpacing:"1.5px", marginBottom:4 }}>Sauce of the Day</div>
                <div style={{ fontFamily:"'Playfair Display',serif", fontSize:18, fontWeight:700, color:"#1a2540" }}>{sauceOfDay.name}</div>
                <div style={{ fontFamily:"'Playfair Display',serif", fontStyle:"italic", fontSize:13, color:sauceOfDay.accent, marginTop:2 }}>{sauceOfDay.tagline}</div>
                <div style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#7888a8", marginTop:6, lineHeight:1.5 }}>{sauceOfDay.description.slice(0,120)}…</div>
              </div>
              <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:6, flexShrink:0 }}>
                <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:getDifficultyColor(sauceOfDay.difficulty), background:getDifficultyColor(sauceOfDay.difficulty)+"15", border:`1px solid ${getDifficultyColor(sauceOfDay.difficulty)}40`, borderRadius:10, padding:"2px 8px" }}>{sauceOfDay.difficulty}</span>
                <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b4c8" }}>⏱ {sauceOfDay.time}</span>
                <span style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:sauceOfDay.accent }}>Open →</span>
              </div>
            </div>
            </>
          )}

          {/* Filter bar */}
          <div style={{ display:"flex", gap:8, marginBottom:8, flexWrap:"wrap", alignItems:"center" }}>
            <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
              {[["all","All"], ...(favorites.size>0?[["saved","♥ Saved"]]:[]), ["mother","Mother"], ["classic","Classics"], ["daughter","Daughters"], ["cold","Cold"], ["stock","Stocks"], ["fish","Fish"], ["chicken","Poultry"], ["beef","Beef"], ["veal","Veal"], ["pork","Pork"], ["shellfish","Shellfish"], ["soup","Soups"], ["vegetable","Vegetables"], ["potato","Potato"], ["dessert","Desserts"], ["eggs","Eggs"], ["bread","Bread"], ["charcuterie","Charcuterie"], ["game","Game"], ["cheese","Cheese"], ["tart","Tarts"], ["rice","Grains"]].map(([v,l]) => (
                <button key={v} className={`cat-chip ${catFilter===v?"on":""}`} onClick={() => setCatFilter(v)}>{l}</button>
              ))}
            </div>
            <div style={{ display:"flex", gap:5, marginLeft:"auto", flexWrap:"wrap" }}>
              {[["all","All levels"],["Easy","Easy"],["Medium","Medium"],["Advanced","Advanced"]].map(([v,l]) => (
                <button key={v} className={`fb ${diffFilter===v?"on":""}`} onClick={() => setDiffFilter(v)} style={{ fontSize:12, padding:"4px 11px" }}>{l}</button>
              ))}
            </div>
          </div>

          {/* Technique filter */}
          <div style={{ display:"flex", gap:5, marginBottom:14, flexWrap:"wrap", alignItems:"center" }}>
            <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", letterSpacing:".8px", textTransform:"uppercase", flexShrink:0 }}>By technique:</span>
            {["all","roux","emulsification","reduction","liaison","clarification","poaching"].map(t => (
              <button
                key={t}
                onClick={() => setTechFilter(t)}
                style={{ background: techFilter===t ? "#f0ecff" : "#fff", border:"1px solid", borderColor: techFilter===t ? "#9070d0" : "#cdd8ea", color: techFilter===t ? "#7050a8" : "#8898b0", cursor:"pointer", padding:"3px 10px", borderRadius:20, fontFamily:"'Crimson Text',serif", fontSize:12, transition:"all .15s", whiteSpace:"nowrap" }}
              >
                {t === "all" ? "All techniques" : t.replace("_tech","").replace(/_/g," ")}
              </button>
            ))}
          </div>

          {/* Result count + sort + view toggle */}
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18, flexWrap:"wrap", gap:8 }}>
            <p style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#a0b4c8", fontStyle:"italic" }}>
              {filtered.length} sauce{filtered.length!==1?"s":""}
              {search && ` matching "${search}"`}
              {catFilter === "saved" && " · Saved"}
              {diffFilter !== "all" && ` · ${diffFilter}`}
              {techFilter !== "all" && ` · ${techFilter}`}
            </p>
            <div style={{ display:"flex", gap:6, alignItems:"center" }}>
              <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#c8d4e0" }}>/ to search · Esc back</span>
              <select
                value={sortBy} onChange={e => setSortBy(e.target.value)}
                style={{ background:"#fff", border:"1px solid #cdd8ea", color:"#6880a8", cursor:"pointer", padding:"4px 8px", borderRadius:6, fontFamily:"'Crimson Text',serif", fontSize:12, outline:"none" }}
              >
                <option value="default">Default order</option>
                <option value="az">A → Z</option>
                <option value="za">Z → A</option>
                <option value="time">Quickest first</option>
                <option value="difficulty">Easiest first</option>
              </select>
              <div style={{ display:"flex", gap:2, background:"#eef2f8", borderRadius:6, padding:2 }}>
                {[["grid","⊞"],["list","≡"]].map(([mode, icon]) => (
                  <button key={mode} onClick={() => setViewMode(mode)} style={{ background: viewMode===mode ? "#fff" : "transparent", border: viewMode===mode ? "1px solid #cdd8ea" : "1px solid transparent", color: viewMode===mode ? "#2060b0" : "#a0b4c8", cursor:"pointer", padding:"3px 8px", borderRadius:4, fontSize:14, transition:"all .15s" }}>{icon}</button>
                ))}
              </div>
            </div>
          </div>

          {/* Recently viewed strip (when not searching) */}
          {!search && catFilter === "all" && diffFilter === "all" && recentlyViewed.length > 0 && (
            <div style={{ marginBottom:24 }}>
              <p style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#b0bcd0", letterSpacing:"1px", textTransform:"uppercase", marginBottom:10 }}>Recently viewed</p>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                {recentlyViewed.map(id => {
                  const s = SAUCES.find(x => x.id === id);
                  return s ? <div key={id} className="tn" style={{ fontSize:12, borderColor: s.accent+"66", color: s.accent }} onClick={() => navigateTo(id)}>{s.name}</div> : null;
                })}
              </div>
            </div>
          )}

          {/* Grid / List */}
          {catFilter === "all" && !search && diffFilter === "all" && techFilter === "all" && sortBy === "default" ? (
            Object.entries(CATEGORIES).map(([cat, meta]) => {
              const list = SAUCES.filter(s => s.category === cat);
              return (
                <div key={cat} style={{ marginBottom:30 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:12 }}>
                    <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:15, color:meta.color, fontStyle:"italic" }}>{meta.label}</h2>
                    <div style={{ flex:1, height:1, background:"#dde8f0" }} />
                    <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#b0c0d8" }}>{list.length}</span>
                  </div>
                  {viewMode === "grid" ? (
                    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(230px,1fr))", gap:10 }}>
                      {list.map(s => (
                        <SauceCard key={s.id} sauce={s} isFav={favorites.has(s.id)} inShop={shopList.has(s.id)} isCooked={cookedIds.has(s.id)} hasNote={!!userNotes[s.id]?.trim()} rating={ratings[s.id]||0} onFav={e => toggleFav(s.id, e)} onShop={e => toggleShop(s.id, e)} onClick={() => navigateTo(s.id)} />
                      ))}
                    </div>
                  ) : (
                    <div style={{ background:"#fff", border:"1px solid #dde8f4", borderRadius:10, overflow:"hidden" }}>
                      {list.map((s, i) => <SauceRow key={s.id} sauce={s} isFav={favorites.has(s.id)} inShop={shopList.has(s.id)} isCooked={cookedIds.has(s.id)} hasNote={!!userNotes[s.id]?.trim()} rating={ratings[s.id]||0} onFav={e => toggleFav(s.id, e)} onShop={e => toggleShop(s.id, e)} onClick={() => navigateTo(s.id)} isLast={i===list.length-1} />)}
                    </div>
                  )}
                </div>
              );
            })
          ) : (
            <>
              {viewMode === "grid" ? (
                <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(230px,1fr))", gap:10 }}>
                  {sortedFiltered.map(s => (
                    <SauceCard key={s.id} sauce={s} isFav={favorites.has(s.id)} inShop={shopList.has(s.id)} isCooked={cookedIds.has(s.id)} hasNote={!!userNotes[s.id]?.trim()} rating={ratings[s.id]||0} onFav={e => toggleFav(s.id, e)} onShop={e => toggleShop(s.id, e)} onClick={() => navigateTo(s.id)} />
                  ))}
                </div>
              ) : (
                <div style={{ background:"#fff", border:"1px solid #dde8f4", borderRadius:10, overflow:"hidden" }}>
                  {sortedFiltered.map((s, i) => <SauceRow key={s.id} sauce={s} isFav={favorites.has(s.id)} inShop={shopList.has(s.id)} isCooked={cookedIds.has(s.id)} hasNote={!!userNotes[s.id]?.trim()} rating={ratings[s.id]||0} onFav={e => toggleFav(s.id, e)} onShop={e => toggleShop(s.id, e)} onClick={() => navigateTo(s.id)} isLast={i===sortedFiltered.length-1} />)}
                </div>
              )}
              {sortedFiltered.length === 0 && (
                <div style={{ textAlign:"center", padding:"40px 20px", color:"#a0b4c8", fontFamily:"'Crimson Text',serif", fontStyle:"italic" }}>
                  No sauces found. <button style={{ background:"none", border:"none", color:"#4878c0", cursor:"pointer", fontFamily:"'Crimson Text',serif", fontStyle:"italic" }} onClick={() => { setSearch(""); setCatFilter("all"); setDiffFilter("all"); setTechFilter("all"); setSortBy("default"); }}>Clear filters</button>
                </div>
              )}
            </>
          )}
        </div>
      )}

      {/* ─── Toast Notifications ─── */}
      {toasts.length > 0 && (
        <div style={{ position:"fixed", bottom:24, right:24, display:"flex", flexDirection:"column", gap:8, zIndex:9999, pointerEvents:"none" }}>
          {toasts.map(t => (
            <div key={t.id} className="toast-enter" style={{ background: darkMode ? "#1e2a3e" : "#fff", border:`1px solid ${darkMode ? "#3a5070" : "#cdd8ea"}`, borderRadius:12, padding:"10px 16px", display:"flex", alignItems:"center", gap:10, boxShadow:"0 6px 24px rgba(0,0,0,.14)", minWidth:200, maxWidth:280 }}>
              <span style={{ fontSize:18, lineHeight:1 }}>{t.icon}</span>
              <span style={{ fontFamily:"'Crimson Text',serif", fontSize:14, color: darkMode ? "#e2e8f0" : "#1a2540", flex:1 }}>{t.msg}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function SauceCard({ sauce, isFav, inShop, isCooked, hasNote, rating, onFav, onShop, onClick }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      className="sc"
      style={{ "--ac": sauce.accent }}
      onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      {/* Status badges */}
      {(isCooked || hasNote) && (
        <div style={{ position:"absolute", top:8, left:10, display:"flex", gap:3 }}>
          {isCooked && <span style={{ fontSize:10, color:"#5ab870", background:"#f0fbf4", border:"1px solid #a8deb8", borderRadius:10, padding:"1px 5px", fontFamily:"'Crimson Text',serif" }}>✓ cooked</span>}
          {hasNote  && <span style={{ fontSize:10, color:"#d4b84a", background:"#fffdf0", border:"1px solid #e8dca8", borderRadius:10, padding:"1px 5px", fontFamily:"'Crimson Text',serif" }}>✏</span>}
        </div>
      )}

      {/* Action buttons */}
      <div style={{ position:"absolute", top:10, right:10, display:"flex", gap:5, opacity: hovered||isFav||inShop ? 1 : 0, transition:"opacity .15s", zIndex:2 }}>
        <button
          onClick={onFav}
          title={isFav ? "Remove from favourites" : "Add to favourites"}
          style={{ background: isFav ? "#fff0f3" : "#f8f9fc", border:"1px solid", borderColor: isFav ? "#e8a0b0" : "#cdd8ea", borderRadius:6, width:28, height:28, cursor:"pointer", fontSize:15, display:"flex", alignItems:"center", justifyContent:"center", transition:"all .15s", color: isFav ? "#d04060" : "#c0c8d8" }}
        >{isFav ? "♥" : "♡"}</button>
        <button
          onClick={onShop}
          title={inShop ? "Remove from list" : "Add to shopping list"}
          style={{ background: inShop ? "#e4edf9" : "#f8f9fc", border:"1px solid", borderColor: inShop ? "#9ab8e0" : "#cdd8ea", borderRadius:6, width:28, height:28, cursor:"pointer", fontSize:13, display:"flex", alignItems:"center", justifyContent:"center", transition:"all .15s", color: inShop ? "#2060b0" : "#a0b4c8", fontWeight: inShop ? "700" : "normal" }}
        >{inShop ? "✓" : "+"}</button>
      </div>

      <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:15, color:"#1a2540", paddingRight: hovered||isFav||inShop ? 70 : 0, transition:"padding .15s", marginTop: isCooked||hasNote ? 16 : 0 }}>{sauce.name}</h3>
      <p style={{ fontFamily:"'Playfair Display',serif", fontStyle:"italic", color:sauce.accent, fontSize:12, marginTop:3, marginBottom:7 }}>{sauce.tagline}</p>
      <p style={{ fontFamily:"'Crimson Text',serif", fontSize:13, color:"#7888a8", lineHeight:1.5 }}>{sauce.description.slice(0,90)}…</p>
      <div style={{ marginTop:10, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#a8b8cc" }}>⏱ {sauce.time}</span>
          <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:getDifficultyColor(sauce.difficulty) }}>{sauce.difficulty}</span>
        </div>
        <div style={{ display:"flex", gap:5, alignItems:"center" }}>
          {rating > 0 && <span style={{ color:"#f0b030", fontSize:11, letterSpacing:"-1px", lineHeight:1 }}>{"★".repeat(rating)}{"☆".repeat(5-rating)}</span>}
          {sauce.children.length > 0 && <span style={{ fontFamily:"'Crimson Text',serif", fontSize:11, color:"#4888c0" }}>{sauce.children.length} daughter{sauce.children.length!==1?"s":""}</span>}
        </div>
      </div>
    </div>
  );
}

function SauceRow({ sauce, isFav, inShop, isCooked, hasNote, rating, onFav, onShop, onClick, isLast }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ display:"flex", alignItems:"center", gap:12, padding:"12px 18px", borderBottom: isLast ? "none" : "1px solid #eef3fa", cursor:"pointer", background: hovered ? "#f7f9fd" : "#fff", transition:"background .12s", position:"relative" }}
    >
      <div style={{ width:4, height:36, borderRadius:2, background:sauce.accent, flexShrink:0 }} />
      <div style={{ flex:1, minWidth:0 }}>
        <div style={{ display:"flex", alignItems:"baseline", gap:8 }}>
          <span style={{ fontFamily:"'Playfair Display',serif", fontSize:14, color:"#1a2540", fontWeight:600 }}>{sauce.name}</span>
          <span style={{ fontFamily:"'Playfair Display',serif", fontStyle:"italic", fontSize:12, color:sauce.accent }}>{sauce.tagline}</span>
          {isCooked && <span style={{ fontSize:10, color:"#5ab870" }}>✓</span>}
          {hasNote  && <span style={{ fontSize:10, color:"#d4b84a" }}>✏</span>}
        </div>
        <div style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a0b0c8", marginTop:2, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
          {sauce.description.slice(0,100)}…
        </div>
      </div>
      <div style={{ display:"flex", gap:10, alignItems:"center", flexShrink:0 }}>
        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:"#a8b8cc", whiteSpace:"nowrap" }}>⏱ {sauce.time}</span>
        <span style={{ fontFamily:"'Crimson Text',serif", fontSize:12, color:getDifficultyColor(sauce.difficulty) }}>{sauce.difficulty}</span>
        {rating > 0 && <span style={{ color:"#f0b030", fontSize:11, letterSpacing:"-1px", lineHeight:1 }}>{"★".repeat(rating)}</span>}
        <div style={{ display:"flex", gap:4, opacity: hovered||isFav||inShop ? 1 : 0, transition:"opacity .12s" }}>
          <button onClick={onFav} style={{ background:"none", border:"none", cursor:"pointer", fontSize:14, color: isFav ? "#d04060" : "#c0c8d8", padding:"2px 4px" }}>{isFav?"♥":"♡"}</button>
          <button onClick={onShop} style={{ background:"none", border:"none", cursor:"pointer", fontSize:13, color: inShop ? "#2060b0" : "#a0b4c8", padding:"2px 4px" }}>{inShop?"✓":"+"}</button>
        </div>
        <span style={{ color:"#c0cce0", fontSize:13 }}>›</span>
      </div>
    </div>
  );
}
